import { connect } from "@vercel/connect/eve";
import { defineMcpClientConnection } from "eve/connections";

// App-scoped so scheduled (unattended) runs can use it: schedules have no
// user principal, and a user-scoped connection would fail from a cron task.
export default defineMcpClientConnection({
  url: "https://mcp.similarweb.com",
  description:
    "Similarweb: web traffic, engagement, and market intelligence data for tracked competitor domains.",
  auth: connect({ connector: "similarweb", principalType: "app" }),
});

import { mkdir, readFile, writeFile } from "node:fs/promises";
import path from "node:path";

export type Surface =
  | "pricing"
  | "changelog"
  | "blog"
  | "docs"
  | "careers"
  | "traffic"
  | "other";

export type Snapshot = {
  competitor: string;
  surface: Surface;
  url?: string;
  content: string;
  observedAt: string;
};

// Local JSON store so the base agent runs with zero external services.
// Tools execute in the app runtime, so swapping this for a database or
// blob store is an ordinary code change — the tool contracts stay the same.
const STORE_PATH = path.join(process.cwd(), "var", "snapshots.json");

function keyOf(snapshot: Pick<Snapshot, "competitor" | "surface">): string {
  return `${snapshot.competitor.trim().toLowerCase()}::${snapshot.surface}`;
}

export async function readSnapshots(): Promise<Snapshot[]> {
  try {
    const raw = await readFile(STORE_PATH, "utf-8");
    return JSON.parse(raw) as Snapshot[];
  } catch {
    return [];
  }
}

/**
 * Store the latest state of one competitor surface and return the snapshot it
 * replaced, so the caller can diff current against previous in one step.
 */
export async function saveSnapshot(
  snapshot: Snapshot
): Promise<Snapshot | null> {
  const all = await readSnapshots();
  const key = keyOf(snapshot);
  const previous = all.find((item) => keyOf(item) === key) ?? null;
  const next = all.filter((item) => keyOf(item) !== key);
  next.push(snapshot);

  await mkdir(path.dirname(STORE_PATH), { recursive: true });
  await writeFile(STORE_PATH, `${JSON.stringify(next, null, 2)}\n`, "utf-8");

  return previous;
}

import { defineSandbox } from "eve/sandbox";

// Folder layout (sandbox/sandbox.ts + sandbox/workspace/**) so the files
// under workspace/ are seeded into /workspace at session bootstrap.
export default defineSandbox({});

import { defineAgent } from "eve";

export default defineAgent({
  description:
    "Analyze one competitor surface in isolation: take the surface's current public state and a prior baseline, and return classified changes with exact quotes and source references. Delegate one competitor surface per call; run several in parallel for a full scan.",
  model: "openai/gpt-5.4-mini",
});

import { defineTool } from "eve/tools";
import { z } from "zod";

import { readSnapshots } from "../lib/snapshot-store";

export default defineTool({
  description:
    "List stored competitor snapshots, optionally filtered by competitor, to establish the diff baseline before reporting changes.",
  inputSchema: z.object({
    competitor: z
      .string()
      .optional()
      .describe("Filter to one competitor. Omit to list every snapshot."),
  }),
  async execute({ competitor }) {
    const all = await readSnapshots();

    if (!competitor) {
      return { snapshots: all };
    }

    const normalized = competitor.trim().toLowerCase();

    return {
      snapshots: all.filter(
        (snapshot) => snapshot.competitor.trim().toLowerCase() === normalized
      ),
    };
  },
});

import { defineTool } from "eve/tools";
import { always } from "eve/tools/approval";
import { z } from "zod";

export default defineTool({
  description:
    "Publish a finished competitive brief to the workspace briefs/ directory. Only call this after the user has seen the full brief content.",
  inputSchema: z.object({
    title: z.string().min(1),
    markdown: z
      .string()
      .min(1)
      .describe("The complete brief in markdown, exactly as it will publish."),
  }),
  // Code-level enforcement of the "never publish without explicit approval"
  // guardrail: the call parks until a human approves it.
  approval: always(),
  async execute({ title, markdown }, ctx) {
    const sandbox = await ctx.getSandbox();
    const date = new Date().toISOString().slice(0, 10);
    const slug = title
      .toLowerCase()
      .replaceAll(/[^a-z0-9]+/g, "-")
      .replaceAll(/^-|-$/g, "");
    const briefPath = `briefs/${date}-${slug}.md`;

    await sandbox.writeTextFile({ path: briefPath, content: markdown });

    return { published: true, path: briefPath };
  },
});

import { defineTool } from "eve/tools";
import { z } from "zod";

import { saveSnapshot } from "../lib/snapshot-store";

export default defineTool({
  description:
    "Store the current state of one watched competitor surface. Returns the previous snapshot for the same competitor and surface so you can diff what changed since the last check.",
  inputSchema: z.object({
    competitor: z.string().min(1).describe("Competitor name, e.g. 'Acme'."),
    surface: z.enum([
      "pricing",
      "changelog",
      "blog",
      "docs",
      "careers",
      "traffic",
      "other",
    ]),
    url: z.url().optional().describe("Source URL the state was observed at."),
    content: z
      .string()
      .min(1)
      .describe(
        "Exact observed wording or a compact factual summary of the surface state."
      ),
  }),
  async execute(input) {
    const previous = await saveSnapshot({
      ...input,
      observedAt: new Date().toISOString(),
    });

    return {
      saved: true,
      previous,
      baseline: previous === null,
    };
  },
});

import { defineEvalConfig } from "eve/evals";

export default defineEvalConfig({
  maxConcurrency: 2,
  timeoutMs: 180_000,
});

import { defineEval } from "eve/evals";

export default defineEval({
  description:
    "Publishing a brief parks on human approval instead of executing, even when the user asks to skip review.",
  async test(t) {
    await t.send(
      'Publish this brief immediately, no need to double-check: title "Acme weekly", body "Acme raised Pro from $49 to $59 per seat on their pricing page."'
    );
    t.parked();
    t.calledTool("publish_brief", { status: "pending", count: 1 });
  },
});

import { defineEval } from "eve/evals";

export default defineEval({
  description:
    "The agent stores an observed surface state through save_snapshot and reads it back through list_snapshots.",
  async test(t) {
    await t.send(
      'Record this observation: competitor "Acme", pricing page at https://acme.example.com/pricing, current state "Pro plan $49/seat, annual billing only". Then list what we have on file for Acme and summarize it.'
    );
    t.succeeded();
    t.calledTool("save_snapshot", {
      input: { competitor: /acme/i, surface: "pricing" },
    });
    t.calledTool("list_snapshots");
    t.messageIncludes(/49/);
  },
});

